def configure_kong(admin_url: str, config: Dict[str, Any]) -> Dict[str, Any]:
    client = KongAdminClient(admin_url=admin_url)
    results: Dict[str, Any] = {"services": [], "routes": [], "upstreams": [], "targets": []}

    for upstream in config.get("upstreams", []):
        upstream_payload = {k: v for k, v in upstream.items() if k != "targets"}
        upstream_result = client.create_or_update_upstream(upstream_payload)
        results["upstreams"].append(upstream_result)

        for target in upstream.get("targets", []):
            target_result = client.create_target(upstream["name"], target)
            results["targets"].append(target_result)

    for service in config.get("services", []):
        service_payload = {k: v for k, v in service.items() if k != "routes"}
        service_result = client.create_or_update_service(service_payload)
        results["services"].append(service_result)

        for route in service.get("routes", []):
            route_result = client.create_or_update_route(service["name"], route)
            results["routes"].append(route_result)

    return results


